action.new_str:
@lexer::members {
    std::string currentFilename = "<unknown>";
    int currentLine = 1;
    int currentCol = 1;
    bool atStartOfLine = true;
    bool hadLeadingSpace = false;

    class PositionedToken : public antlr4::CommonToken {
    public:
        PositionedToken(size_t type, const std::string &text, const std::string &filename, int line, int col, bool startOfLine, bool leadingSpace)
            : CommonToken(type, text), 
              filename(filename), 
              col(col), 
              startOfLine(startOfLine), 
              leadingSpace(leadingSpace) {}

        std::string filename;
        int col;
        bool startOfLine;
        bool leadingSpace;
    };

    void handlePreprocessorDirective(const std::string& text) {
        std::istringstream iss(text.substr(1));
        int lineNum;
        std::string filename;

        if (iss >> lineNum) {
            currentLine = lineNum;

            // Extract filename (may be quoted)
            std::getline(iss, filename);

            // Remove flags part
            size_t spacePos = filename.find(' ');
            if (spacePos != std::string::npos) {
                filename = filename.substr(0, spacePos);
            }

            // Remove quotes if present
            if (filename.size() >= 2 && filename.front() == '"' && filename.back() == '"') {
                filename = filename.substr(1, filename.size() - 2);
            }

            currentFilename = filename;
            currentCol = 1;
            atStartOfLine = true;
            hadLeadingSpace = false;
        }
    }

